        sum.x += val.x;
        sum.y += val.y;
        sum.z += val.z;
        sum.w += val.w;
    }

    // Combine partial sums from float4
    float total_sum = sum.x + sum.y + sum.z + sum.w;

    // 2. Handle the remaining elements (Tail part)
